    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "table": "candles60s",
        //         "data": [
        //             {
        //                 "marketCode": "BTC-USD-SWAP-LIN",
        //                 "candle": [
        //                     "1594313762698", //timestamp
        //                     "9633.1",        //open
        //                     "9693.9",        //high
        //                     "9238.1",        //low
        //                     "9630.2",        //close
        //                     "45247",         //volume in OX
        //                     "5.3"            //volume in Contracts
        //                 ]
        //             }
        //         ]
        //     }
        //
        Object table = this.safeString(message, "table");
        Object parts = Helpers.split(table, "candles");
        Object timeframeId = this.safeString(parts, 1, "");
        Object timeframe = this.findTimeframe(timeframeId);
        Object messageData = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object data = this.safeDict(messageData, 0, new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(data, "marketCode");
        Object market = this.safeMarket(marketId);
        Object symbol = this.safeSymbol(marketId, market);
        if (!Helpers.isTrue((Helpers.inOp(this.ohlcvs, symbol))))
        {
            Helpers.addElementToObject(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}});
        }
        if (!Helpers.isTrue((Helpers.inOp(Helpers.GetValue(this.ohlcvs, symbol), timeframe))))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue()));
        }
        Object candle = this.safeList(data, "candle", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object parsed = this.parseWsOHLCV(candle, market);
        Object stored = Helpers.GetValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("ohlcv:", symbol), ":"), timeframe);
        client.resolve(stored, messageHash);
        // for multiOHLCV we need special object, as opposed to other "multi"
        // methods, because OHLCV response item does not contain symbol
        // or timeframe, thus otherwise it would be unrecognizable
        Object messageHashForMulti = Helpers.add("multi:", messageHash);
        client.resolve(new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol, timeframe, stored)), messageHashForMulti);
    }

