    public void handleOrderBook(Client client, Object message)
    {
        //
        //     {
        //         "table": "depth",
        //         "data": {
        //             "seqNum": "100170478917895032",
        //             "asks": [
        //                 [ 0.01, 100500 ],
        //                 ...
        //             ],
        //             "bids": [
        //                 [ 69.69696, 69 ],
        //                 ...
        //             ],
        //             "checksum": 261021645,
        //             "marketCode": "OX-USDT",
        //             "timestamp": 1716204786184
        //         },
        //         "action": "partial"
        //     }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(data, "marketCode");
        Object symbol = this.safeSymbol(marketId);
        Object timestamp = this.safeInteger(data, "timestamp");
        Object messageHash = Helpers.add("orderbook:", symbol);
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}));
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object snapshot = this.parseOrderBook(data, symbol, timestamp, "asks", "bids");
        Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(data, "seqNum"));
        Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        client.resolve(orderbook, messageHash);
    }

