    public Object parseWsBidAsk(Object ticker, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "marketCode");
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeString(market, "symbol");
        Object timestamp = this.safeInteger(ticker, "timestamp");
        Object ask = this.safeList(ticker, "ask", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object bid = this.safeList(ticker, "bid", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", OxfunCore.this.iso8601(timestamp) );
            put( "ask", OxfunCore.this.safeNumber(ask, 0) );
            put( "askVolume", OxfunCore.this.safeNumber(ask, 1) );
            put( "bid", OxfunCore.this.safeNumber(bid, 0) );
            put( "bidVolume", OxfunCore.this.safeNumber(bid, 1) );
            put( "info", ticker );
        }}, market);
    }

